import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { productService } from '../../services/api'
import { showToast } from '../../utils/toast'
import PondChartCard from '../../components/charts/PondChartCard'
import '../../styles/product-management.css'

const emptyOverview = {
  totalCategories: 0,
  totalProducts: 0,
  totalSuppliers: 0,
  topCategory: null,
  categoryStats: [],
  supplierStats: [],
  topProducts: [],
}

const PAGE_SIZE = 8

const formatDateTime = (value) => {
  if (!value) return '-'
  const d = new Date(value)
  if (Number.isNaN(d.getTime())) return value
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  }).format(d)
}

const formatCurrency = (v) =>
  `${Number(v || 0).toLocaleString('vi-VN')} đ`

const ProductManagementPage = ({ roleLabel = 'Owner' }) => {
  const [loading, setLoading] = useState(true)
  const [overview, setOverview] = useState(emptyOverview)
  const [categories, setCategories] = useState([])
  const [products, setProducts] = useState([])

  const [tab, setTab] = useState('products')

  const [productSearch, setProductSearch] = useState('')
  const [categorySearch, setCategorySearch] = useState('')

  const [productPage, setProductPage] = useState(1)
  const [categoryPage, setCategoryPage] = useState(1)

  const fetchData = useCallback(async () => {
    try {
      setLoading(true)
      const [o, c, p] = await Promise.all([
        productService.getProductOverview(),
        productService.getProductCategories(),
        productService.getProducts(),
      ])

      setOverview(o?.data?.data || emptyOverview)
      setCategories(c?.data?.data || [])
      setProducts(p?.data?.data || [])
    } catch (e) {
      showToast({ title: 'Không tải được dữ liệu', type: 'error' })
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchData()
  }, [fetchData])

  const totalSuppliers = useMemo(() => {
    return new Set(products.map(p => p.supplier).filter(Boolean)).size
  }, [products])

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      p.product_name?.toLowerCase().includes(productSearch.toLowerCase())
    )
  }, [products, productSearch])

  const filteredCategories = useMemo(() => {
    return categories.filter(c =>
      c.category_name?.toLowerCase().includes(categorySearch.toLowerCase())
    )
  }, [categories, categorySearch])

  const productPaged = filteredProducts.slice(
    (productPage - 1) * PAGE_SIZE,
    productPage * PAGE_SIZE
  )

  const categoryPaged = filteredCategories.slice(
    (categoryPage - 1) * PAGE_SIZE,
    categoryPage * PAGE_SIZE
  )

  if (loading) {
    return (
      <div className="dashboard product-management_page">
        <div className="flex-center" style={{ height: '100vh' }}>
          <div className="spinner" />
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard product-management_page">

      {/* HEADER */}
      <div className="stats-header">
        <div>
          <h1>Quản lý sản phẩm</h1>
          <p>Quản lý danh mục và sản phẩm trong trại nuôi</p>
        </div>

        <div className="header-actions">
          <button className="btn btn-primary">+ Thêm sản phẩm</button>
          <button className="btn btn-secondary">+ Thêm danh mục</button>
        </div>
      </div>

      {/* STATS */}
      <div className="stats-grid">

        <div className="stats-card stats-card--primary">
          <span>📂</span>
          <div>
            <p>Tổng danh mục</p>
            <h2>{overview.totalCategories}</h2>
            <small>Dữ liệu {roleLabel}</small>
          </div>
        </div>

        <div className="stats-card stats-card--success">
          <span>🧪</span>
          <div>
            <p>Tổng sản phẩm</p>
            <h2>{overview.totalProducts}</h2>
          </div>
        </div>

        <div className="stats-card stats-card--warning">
          <span>🏷️</span>
          <div>
            <p>Nhà cung cấp</p>
            <h2>{totalSuppliers}</h2>
          </div>
        </div>

        <div className="stats-card stats-card--info">
          <span>⭐</span>
          <div>
            <p>Danh mục nổi bật</p>
            <h2>{overview.topCategory?.label || '-'}</h2>
          </div>
        </div>

      </div>

      {/* CHART */}
      <div className="chart-grid">
        <PondChartCard
          prefix="product-management"
          title="Sản phẩm theo danh mục"
          type="doughnut"
          data={(overview.categoryStats || []).map((x, i) => ({
            label: x.label,
            value: x.value,
          }))}
        />

        <PondChartCard
          prefix="product-management"
          title="Nhà cung cấp"
          type="bar"
          data={(overview.supplierStats || []).map(x => ({
            label: x.label,
            value: x.value,
          }))}
        />

        <PondChartCard
          prefix="product-management"
          title="Top sản phẩm"
          type="bar"
          data={(overview.topProducts || []).map(x => ({
            label: x.label,
            value: x.value,
          }))}
        />
      </div>

      {/* TABS */}
      <div className="tabs">
        <button
          className={tab === 'products' ? 'active' : ''}
          onClick={() => setTab('products')}
        >
          Sản phẩm
        </button>

        <button
          className={tab === 'categories' ? 'active' : ''}
          onClick={() => setTab('categories')}
        >
          Danh mục
        </button>
      </div>

      {/* TABLE */}
      <div className="table-card">

        {tab === 'products' ? (
          <>
            <div className="table-header">
              <h2>Sản phẩm</h2>
              <input
                placeholder="Tìm sản phẩm..."
                value={productSearch}
                onChange={(e) => setProductSearch(e.target.value)}
              />
            </div>

            <table className="table">
              <thead>
                <tr>
                  <th>Tên</th>
                  <th>Nhà cung cấp</th>
                  <th>Đơn vị</th>
                  <th>Giá</th>
                  <th>Cập nhật</th>
                </tr>
              </thead>

              <tbody>
                {productPaged.map(p => (
                  <tr key={p.product_id}>
                    <td>{p.product_name}</td>
                    <td>{p.supplier || '-'}</td>
                    <td>{p.unit}</td>
                    <td>{formatCurrency(p.unit_price)}</td>
                    <td>{formatDateTime(p.updated_at)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </>
        ) : (
          <>
            <div className="table-header">
              <h2>Danh mục</h2>
              <input
                placeholder="Tìm danh mục..."
                value={categorySearch}
                onChange={(e) => setCategorySearch(e.target.value)}
              />
            </div>

            <table className="table">
              <thead>
                <tr>
                  <th>Tên</th>
                  <th>Số sản phẩm</th>
                  <th>Cập nhật</th>
                </tr>
              </thead>

              <tbody>
                {categoryPaged.map(c => (
                  <tr key={c.category_id}>
                    <td>{c.category_name}</td>
                    <td>{c.product_count}</td>
                    <td>{formatDateTime(c.updated_at)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </>
        )}

      </div>

    </div>
  )
}

export default ProductManagementPage
